import { forwardRef, type ReactElement } from "react";
import type { TextFieldProps } from "react-aria-components";
import { TextField, Label as AriaLabel, Text } from "react-aria-components";
import { Label } from "../Label";
import type { LabelCustomProps } from "../Label";
import { Hint } from "../Hint";
import type { HintCustomProps } from "../Hint";
import { ValidationMessage } from "../ValidationMessage";
import type {
  ValidationMessageValidProps,
  ValidationMessageInvalidProps,
} from "../ValidationMessage";
import * as styles from "./FormField.css";
import { clsx } from "clsx";

export type FormFieldLabel = Omit<LabelCustomProps, "asChild">;

export type FormFieldHint = HintCustomProps;

export type FormFieldValidationMessage =
  | ValidationMessageValidProps
  | ValidationMessageInvalidProps;

interface FormFieldCustomProps {
  /**
   * The label configuration
   */
  label?: FormFieldLabel;

  /**
   * The hint configuration (displayed below the label)
   */
  hint?: FormFieldHint;

  /**
   * The validation message configuration
   */
  validationMessage?: FormFieldValidationMessage;

  /**
   * Optional input ID (auto-generated if not provided)
   */
  inputId?: string;

  /**
   * The input component (must be a valid React element)
   */
  children: ReactElement;
}

export interface FormFieldProps
  extends
    Omit<TextFieldProps, keyof FormFieldCustomProps>,
    FormFieldCustomProps {}

export const FormField = forwardRef<HTMLDivElement, FormFieldProps>(
  (
    {
      label,
      hint,
      validationMessage,
      inputId,
      children,
      className,
      ...textFieldProps
    },
    ref
  ) => {
    return (
      <TextField
        ref={ref}
        className={clsx(styles.formField, className)}
        isInvalid={validationMessage?.variant === "invalid"}
        {...(inputId !== undefined && { id: inputId })}
        {...textFieldProps}
      >
        {(label || hint) && (
          <div className={styles.labelHintStack}>
            {label && (
              <Label
                asChild
                {...(label.required !== undefined && {
                  required: label.required,
                })}
                {...(label.variant !== undefined && { variant: label.variant })}
              >
                <AriaLabel>{label.children}</AriaLabel>
              </Label>
            )}
            {hint && (
              <Text elementType="div" slot="description">
                <Hint>{hint.children}</Hint>
              </Text>
            )}
          </div>
        )}
        {children}
        {validationMessage && (
          <Text slot="errorMessage" elementType="div">
            <ValidationMessage {...validationMessage}>
              {validationMessage.children}
            </ValidationMessage>
          </Text>
        )}
      </TextField>
    );
  }
);

FormField.displayName = "FormField";
